Public parameters: generator g and random elements M, N of group \mathbb{G} of prime order p; hash function \mathsf{H}: \mathcal{X} \to \{0,1\}^\kappa

\frac{\mathcal{P} \text{ on (NewSession}, sid, \mathcal{P}, \mathcal{P}', pw, \text{client}):}{x \leftarrow_{\mathbb{R}} \mathbb{Z}_p}
X \leftarrow g^x \cdot M^{pw}
\hat{Y} \leftarrow Y/N^{pw}
K \leftarrow \mathsf{H}(sid, \mathcal{P}, \mathcal{P}', X, Y, pw, \hat{Y}^x)
output K

\frac{\mathcal{P}' \text{ on (NewSession}, sid, \mathcal{P}', \mathcal{P}, pw', \text{server}):}{y \leftarrow_{\mathbb{R}} \mathbb{Z}_p}
Y \leftarrow g^y \cdot N^{pw'}
\hat{X} \leftarrow X/M^{pw'}
K' \leftarrow \mathsf{H}(sid, \mathcal{P}, \mathcal{P}', X, Y, pw', \hat{X}^y)
output K'
